/**
 * @name Path traversal in DefaultServlet - direct file serving
 * @description Finds cases where user-controlled HTTP input flows to file system operations in DefaultServlet
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-default-servlet
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File construction sinks
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get() or Path.resolve()
    exists(MethodCall mc |
      (mc.getMethod().hasName("get") and mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths")
       or
       mc.getMethod().hasName("resolve") and mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path"))
      and sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileInputStream construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
  and sink.getNode().getEnclosingCallable().getDeclaringType().getName().matches("%Servlet%")
select sink.getNode(), source, sink, "Potential path traversal: user input flows to file system operation in $@",
  sink.getNode().getEnclosingCallable().getDeclaringType(),
  sink.getNode().getEnclosingCallable().getDeclaringType().getName()
